"""Unit tests for the order_processing module"""

import unittest
import logging
from src.order_processing import (
    calculate_total, 
    process_order, 
    validate_item, 
    InvalidItemError, 
    OrderProcessingError
)

class TestOrderProcessing(unittest.TestCase):

    def setUp(self):
        """Set up test environment"""
        # Suppress logging output during tests
        logging.disable(logging.CRITICAL)

    def tearDown(self):
        """Tear down test environment"""
        # Re-enable logging
        logging.disable(logging.NOTSET)

    def test_calculate_total_valid(self):
        """Test calculate_total with valid items"""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2', 'price': 20.5}
        ]
        self.assertAlmostEqual(calculate_total(items), 30.5)

    def test_calculate_total_empty(self):
        """Test calculate_total with an empty list"""
        self.assertAlmostEqual(calculate_total([]), 0.0)

    def test_calculate_total_invalid(self):
        """Test calculate_total with invalid items"""
        items = [
            {'name': 'Item 1', 'price': 10.0},
            {'name': 'Item 2'}  # Missing price
        ]
        with self.assertRaises(InvalidItemError):
            calculate_total(items)

    def test_process_order_valid(self):
        """Test process_order with valid items"""
        items = [
            {'name': 'Item 1', 'price': 15.0},
            {'name': 'Item 2', 'price': 25.0}
        ]
        order = process_order('ORD-003', items)
        self.assertEqual(order['order_id'], 'ORD-003')
        self.assertAlmostEqual(order['total'], 40.0)
        self.assertEqual(order['status'], 'processed')

    def test_process_order_invalid(self):
        """Test process_order with invalid items"""
        items = [
            {'name': 'Item 1', 'price': 15.0},
            {'name': 'Item 2'} # Missing price
        ]
        with self.assertRaises(OrderProcessingError):
            process_order('ORD-004', items)

    def test_validate_item_valid(self):
        """Test validate_item with a valid item"""
        item = {'name': 'Test Item', 'price': 5.0}
        self.assertTrue(validate_item(item))

    def test_validate_item_invalid_missing_price(self):
        """Test validate_item with a missing price"""
        item = {'name': 'Test Item'}
        self.assertFalse(validate_item(item))

    def test_validate_item_invalid_missing_name(self):
        """Test validate_item with a missing name"""
        item = {'price': 10.0}
        self.assertFalse(validate_item(item))

    def test_validate_item_invalid_data_types(self):
        """Test validate_item with invalid data types"""
        item = {'name': 123, 'price': '10.0'}
        self.assertFalse(validate_item(item))

if __name__ == '__main__':
    unittest.main()

"""Main application entry point"""

import logging
from src.order_processing import process_order, OrderProcessingError

# Set up logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler("logs/app.log"),
        logging.StreamHandler()
    ]
)

if __name__ == '__main__':
    # Test cases
    valid_items = [
        {'name': 'Laptop', 'price': 1200.00},
        {'name': 'Mouse', 'price': 25.50}
    ]
    invalid_items = [
        {'name': 'Keyboard', 'price': 75.00},
        {'name': 'Webcam'}  # Missing price
    ]

    # Process a valid order
    try:
        order_result = process_order('ORD-101', valid_items)
        logging.info(f"Order processed successfully: {order_result}")
    except OrderProcessingError as e:
        logging.error(f"Error processing order ORD-101: {e}")

    # Process an invalid order
    try:
        process_order('ORD-102', invalid_items)
    except OrderProcessingError as e:
        logging.error(f"Error processing order ORD-102: {e}")

